#include <dlib/image_processing.h>
#include <dlib/data_io.h>
#include <iostream>

using namespace dlib;
using namespace std;

// ----------------------------------------------------------------------------------------
std::vector<std::vector<double> > get_interocular_distances(const std::vector<std::vector<full_object_detection> >& objects	);
// ----------------------------------------------------------------------------------------

int main(int argc, char** argv)
{
	try
	{
		const std::string faces_directory = "shape_predictor_194_face_landmarks";
		dlib::array<array2d<unsigned char> > images_train, images_test;
		std::vector<std::vector<full_object_detection> > faces_train, faces_test;
		load_image_dataset(images_train, faces_train, faces_directory + "/shape_predictor_194_face_landmarks.xml");
		load_image_dataset(images_test, faces_test, faces_directory + "/shape_predictor_194_face_landmarks_test.xml");
		shape_predictor_trainer trainer;

		trainer.set_cascade_depth(10);
		trainer.set_tree_depth(4);
		trainer.set_num_trees_per_cascade_level(500);
		trainer.set_nu(0.1);
		trainer.set_oversampling_amount(20);
		trainer.set_feature_pool_size(400);
		trainer.set_lambda(0.1);
		trainer.set_num_test_splits(20);
		trainer.set_feature_pool_region_padding(0);
		trainer.set_num_threads(2);

		shape_predictor sp = trainer.train(images_train, faces_train);
		cout << "mean training error: " <<
			test_shape_predictor(sp, images_train, faces_train, get_interocular_distances(faces_train)) << endl;
		cout << "mean testing error:  " <<
			test_shape_predictor(sp, images_test, faces_test, get_interocular_distances(faces_test)) << endl;

		// Finally, we save the model to disk so we can use it later.
		serialize("shape_predictor_194_face_landmarks/shape_predictor_194_face_landmarks.dat") << sp;
	}
	catch (exception& e)
	{
		cout << "\nexception thrown!" << endl;
		cout << e.what() << endl;
	}
}

// ----------------------------------------------------------------------------------------

double interocular_distance(
	const full_object_detection& det
	)
{
	dlib::vector<double, 2> l, r;
	double cnt = 0;
	// Find the center of the left eye by averaging the points around 
	// the eye.
	for (unsigned long i = 36; i <= 41; ++i)
	{
		l += det.part(i);
		++cnt;
	}
	l /= cnt;

	// Find the center of the right eye by averaging the points around 
	// the eye.
	cnt = 0;
	for (unsigned long i = 42; i <= 47; ++i)
	{
		r += det.part(i);
		++cnt;
	}
	r /= cnt;

	// Now return the distance between the centers of the eyes
	return length(l - r);
}

std::vector<std::vector<double> > get_interocular_distances(
	const std::vector<std::vector<full_object_detection> >& objects
	)
{
	std::vector<std::vector<double> > temp(objects.size());
	for (unsigned long i = 0; i < objects.size(); ++i)
	{
		for (unsigned long j = 0; j < objects[i].size(); ++j)
		{
			temp[i].push_back(interocular_distance(objects[i][j]));
		}
	}
	return temp;
}

// ----------------------------------------------------------------------------------------

