you can use the permissions function to ask for location permission, and then use a fallback intent, preferably with an in-context to check if permission was granted:

```python
@assist.action('my-intent')
def my_intent_action():
    context_manager.add('request_permission')
    return permission(['DEVICE_PRECISE_LOCATION'], 'some context here')

@assist.action('permission-fallback', is_fallback=True, with_context=['request_permission'])
def use_location():
    if _is_permission_granted():
        geo = request['originalRequest']['data'] \
                ['device']['location']['coordinates']
        lat, lng = geo['latitude'], geo['longitude']
        # do something with lat, lng
    else:
        return tell("Sorry, we need your location")

def _is_permission_granted():
    try:
        args = next(input['arguments'] for input in
                    request['originalRequest']['data']['inputs']
                    if input['intent'] == 'actions.intent.PERMISSION')

        return [] != [arg for arg in args
                if arg['textValue'] == 'true' and arg['name'] == 'PERMISSION']
    except:
        return False

```

